<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="类型名称"
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入产品类型名称"
                  v-model:value="queryParams.productTypeName"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a-button style="margin-left: 8px" @click="reset">重置</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="productTypeId"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
        <template #isValid="{ text }">
          {{text=="1" ? '是':'否'}}
        </template>
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>
  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="编号" name="code">
            <a-input placeholder="请输入产品编号" v-model:value="form.code" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item
            label="产品类型名称"
            name="productTypeName"
          >
            <a-input
              placeholder="请输入产品类型名称"
              v-model:value="form.productTypeName"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="是否可用">
            <a-radio-group v-model:value="form.isValid">
              <a-radio :value="1">是</a-radio>
              <a-radio :value="2">否</a-radio>
            </a-radio-group>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="产品类型描述">
            <a-textarea
              rows="4"
              placeholder="请输入产品类型描述"
              v-model:value="form.remark"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "ID",
    dataIndex: "productTypeId",
  },
  {
    title: "编号",
    dataIndex: "code",
  },
  {
    title: "产品类型名称",
    dataIndex: "productTypeName",
  },
  {
    title: "是否可用",
    dataIndex: "isValid",
    slots: { customRender: "isValid" },
  },
  {
    title: "产品类型描述",
    dataIndex: "remark",
    slots: { customRender: "remark" },
  },
];
const rules = {
  code: [{ required: true, message: "该为必填项", trigger: "blur" }],
  productTypeName: [{ required: true, message: "该为必填项", trigger: "blur" }],
};
import { message } from "ant-design-vue";
import {
  ProductTypeList,
  addProductType,
  getProductType,
  delProductType,
  editProductType,
} from "@/server/http/api/Product";
export default {
  name: "QueryList",
  components: {},
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      rules:rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {},
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        productTypeName: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },
  methods: {
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      ProductTypeList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    reset() {
      this.queryParams = {
        current: 1,
        size: 10,
        productTypeName: undefined,
      };
      this.getList();
    },
    handleOk(e) {
      if (
        !this.form.code ||
        !this.form.productTypeName
      ) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      this.form = {};
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onClear() {
      this.$message.info("您清空了勾选的所有行");
    },
    onStatusTitleClick() {
      this.$message.info("你点击了状态栏表头");
    },
    onChange(e) {
      this.$message.info("表格状态改变了");
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      //this.reset();
      this.open = true;
      this.title = "添加分类";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getProductType(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改分类";
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.productTypeId != null) {
        editProductType(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addProductType(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delProductType(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
